sql.where:
a.deleted = 0

    AND a.activity_name LIKE concat('%',#{activityName},'%')


    AND a.biz_type = #{bizType}


    AND a.status = #{status}

mapper.select:
select 
from mk_flash_sale_activity a


    order by ${sidx} ${order}
    order by a.id desc

limit #{offset}, #{limit}

select p.id, p.activity_id as activityId, p.product_id as productId,
       p.flash_sale_price as flashSalePrice, p.activity_stock as activityStock, p.sold_count as soldCount,
       (case #{bizType}
            when 2 then (select cardName from fit_card where fitCardId = p.product_id)
            when 3 then (select card_name from vip_benefit_card where vip_card_id = p.product_id)
            else (select product_name from pt_product where id = p.product_id)
       end) as productName,
       (case #{bizType}
            when 2 then (select cardPrice from fit_card where fitCardId = p.product_id)
            when 3 then (select price from vip_benefit_card where vip_card_id = p.product_id)
            else (select sale_price from pt_product where id = p.product_id)
       end) as originPrice
from mk_flash_sale_product p
where p.activity_id = #{activityId} and p.deleted = 0
order by p.id asc

choose.otherwise:
select product_name as name, sale_price as salePrice,
       (case when listing_status = 1 and deleted = 0 then 1 else 0 end) as listing
from pt_product where id = #{productId}
